108	static njs_promise_t *
109	njs_promise_alloc(njs_vm_t *vm)
110	{
111	    njs_promise_t       *promise;
112	    njs_promise_data_t  *data;
113	
114	    promise = njs_mp_alloc(vm->mem_pool, sizeof(njs_promise_t)
115	                           + sizeof(njs_promise_data_t));
116	    if (njs_slow_path(promise == NULL)) {
117	        goto memory_error;
118	    }
119	
120	    njs_flathsh_init(&promise->object.hash);
121	    njs_flathsh_init(&promise->object.shared_hash);
122	    promise->object.type = NJS_PROMISE;
123	    promise->object.shared = 0;
124	    promise->object.extensible = 1;
125	    promise->object.error_data = 0;
126	    promise->object.fast_array = 0;
127	    promise->object.__proto__ = njs_vm_proto(vm, NJS_OBJ_TYPE_PROMISE);
128	    promise->object.slots = NULL;
129	
130	    data = (njs_promise_data_t *) ((uint8_t *) promise + sizeof(njs_promise_t));
131	
132	    data->state = NJS_PROMISE_PENDING;
133	    data->is_handled = 0;
134	
135	    njs_queue_init(&data->fulfill_queue);
136	    njs_queue_init(&data->reject_queue);
137	
138	    njs_set_data(&promise->value, data, 0);
139	
140	    return promise;
141	
142	memory_error:
143	
144	    njs_memory_error(vm);
145	
146	    return NULL;
147	}
148	
149	
150	njs_int_t
151	njs_promise_constructor(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
152	    njs_index_t unused, njs_value_t *retval)
153	{
154	    njs_promise_t   *promise;
155	    njs_function_t  *function;
156	
157	    if (njs_slow_path(!vm->top_frame->ctor)) {
158	        njs_type_error(vm, "the Promise constructor must be called with new");
159	        return NJS_ERROR;
160	    }
161	
162	    if (njs_slow_path(!njs_is_function(njs_arg(args, nargs, 1)))) {
163	        njs_type_error(vm, "unexpected arguments");
164	        return NJS_ERROR;
165	    }
166	
167	    function = njs_function(njs_argument(args, 1));
168	
169	    promise = njs_promise_constructor_call(vm, function);
170	    if (njs_slow_path(promise == NULL)) {
171	        return NJS_ERROR;
172	    }
173	
174	    njs_set_promise(retval, promise);
175	
176	    return NJS_OK;
177	}
178	
179	
180	njs_int_t
181	njs_vm_promise_create(njs_vm_t *vm, njs_value_t *retval, njs_value_t *callbacks)
182	{
183	    njs_int_t      ret;
184	    njs_promise_t  *promise;
185	
186	    promise = njs_promise_alloc(vm);
187	    if (njs_slow_path(promise == NULL)) {
188	        return NJS_ERROR;
189	    }
190	
191	    ret = njs_promise_create_resolving_functions(vm, promise, callbacks);
192	    if (njs_slow_path(ret != NJS_OK)) {
193	        return NJS_ERROR;
194	    }
195	
196	    njs_set_promise(retval, promise);
197	
198	    return NJS_OK;
199	}
200	
201	
202	static njs_promise_t *
203	njs_promise_constructor_call(njs_vm_t *vm, njs_function_t *function)
204	{
205	    njs_int_t      ret;
206	    njs_value_t    retval, arguments[2];
207	    njs_promise_t  *promise;
208	
209	    promise = njs_promise_alloc(vm);
210	    if (njs_slow_path(promise == NULL)) {
211	        return NULL;
212	    }
213	
214	    ret = njs_promise_create_resolving_functions(vm, promise, arguments);
215	    if (njs_slow_path(ret != NJS_OK)) {
216	        return NULL;
217	    }
218	
219	    ret = njs_function_call(vm, function, &njs_value_undefined, arguments, 2,
220	                            &retval);
221	    if (njs_slow_path(ret != NJS_OK)) {
222	        if (njs_slow_path(njs_is_memory_error(vm, &vm->exception))) {
223	            return NULL;
224	        }
225	
226	        retval = njs_vm_exception(vm);
227	
228	        ret = njs_function_call(vm, njs_function(&arguments[1]),
229	                                &njs_value_undefined, &retval, 1, &retval);
230	        if (njs_slow_path(ret != NJS_OK)) {
231	            return NULL;
232	        }
233	    }
234	
235	    return promise;
236	}
237	
238	
239	njs_function_t *
240	njs_promise_create_function(njs_vm_t *vm, size_t context_size)
241	{
242	    njs_function_t         *function;
243	    njs_promise_context_t  *context;
244	
245	    function = njs_mp_zalloc(vm->mem_pool, sizeof(njs_function_t));
246	    if (njs_slow_path(function == NULL)) {
247	        goto memory_error;
248	    }
249	
250	    if (context_size > 0) {
251	        context = njs_mp_zalloc(vm->mem_pool, context_size);
252	        if (njs_slow_path(context == NULL)) {
253	            njs_mp_free(vm->mem_pool, function);
254	            goto memory_error;
255	        }
256	
257	    } else {
258	        context = NULL;
259	    }
260	
261	    function->object.__proto__ = njs_vm_proto(vm, NJS_OBJ_TYPE_FUNCTION);
262	    function->object.shared_hash = vm->shared->arrow_instance_hash;
263	    function->object.type = NJS_FUNCTION;
264	    function->object.extensible = 1;
265	    function->native = 1;
266	    function->context = context;
267	
268	    return function;
269	
270	memory_error:
271	
272	    njs_memory_error(vm);
273	
274	    return NULL;
275	}
276	
277	
278	static njs_int_t
279	njs_promise_create_resolving_functions(njs_vm_t *vm, njs_promise_t *promise,
280	    njs_value_t *dst)
281	{
282	    unsigned               i;
283	    njs_function_t         *function;
284	    njs_promise_context_t  *context, *resolve_context;
285	
286	    i = 0;
287	
288	    /* Some compilers give at error an uninitialized context if using for. */
289	    do {
290	        function = njs_promise_create_function(vm,
291	                                               sizeof(njs_promise_context_t));
292	        if (njs_slow_path(function == NULL)) {
293	            return NJS_ERROR;
294	        }
295	
296	        function->args_count = 1;
297	
298	        context = function->context;
299	        context->resolved_ref = &context->resolved;
300	
301	        njs_set_promise(&context->promise, promise);
302	        njs_set_function(&dst[i], function);
303	
304	    } while (++i < 2);
305	
306	    njs_function(&dst[0])->u.native = njs_promise_resolve_function;
307	    njs_function(&dst[1])->u.native = njs_promise_reject_function;
308	
309	    resolve_context = njs_function(&dst[0])->context;
310	    resolve_context->resolved_ref = &context->resolved;
311	
312	    return NJS_OK;
313	}
314	
315	
316	njs_promise_capability_t *
317	njs_promise_new_capability(njs_vm_t *vm, njs_value_t *constructor)
318	{
319	    njs_int_t                 ret;
320	    njs_value_t               argument, this;
321	    njs_object_t              *object;
322	    njs_function_t            *function;
323	    njs_promise_context_t     *context;
324	    njs_promise_capability_t  *capability;
325	
326	    object = NULL;
327	    function = NULL;
328	
329	    ret = njs_promise_value_constructor(vm, constructor, constructor);
330	    if (njs_slow_path(ret != NJS_OK)) {
331	        return NULL;
332	    }
333	
334	    capability = njs_mp_zalloc(vm->mem_pool, sizeof(njs_promise_capability_t));
335	    if (njs_slow_path(capability == NULL)) {
336	        njs_memory_error(vm);
337	        return NULL;
338	    }
339	
340	    function = njs_promise_create_function(vm, sizeof(njs_promise_context_t));
341	    if (njs_slow_path(function == NULL)) {
342	        return NULL;
343	    }
344	
345	    njs_set_undefined(&capability->resolve);
346	    njs_set_undefined(&capability->reject);
347	
348	    function->u.native = njs_promise_capability_executor;
349	    function->args_count = 2;
350	
351	    context = function->context;
352	    context->capability = capability;
353	
354	    njs_set_function(&argument, function);
355	
356	    object = njs_function_new_object(vm, constructor);
357	    if (njs_slow_path(object == NULL)) {
358	        return NULL;
359	    }
360	
361	    njs_set_object(&this, object);
362	
363	    ret = njs_function_call2(vm, njs_function(constructor), &this,
364	                             &argument, 1, &capability->promise, 1);
365	    if (njs_slow_path(ret != NJS_OK)) {
366	        return NULL;
367	    }
368	
369	    if (njs_slow_path(!njs_is_function(&capability->resolve))) {
370	        njs_type_error(vm, "capability resolve slot is not callable");
371	        return NULL;
372	    }
373	
374	    if (njs_slow_path(!njs_is_function(&capability->reject))) {
375	        njs_type_error(vm, "capability reject slot is not callable");
376	        return NULL;
377	    }
378	
379	    return capability;
380	}
381	
382	
383	static njs_int_t
384	njs_promise_value_constructor(njs_vm_t *vm, njs_value_t *value,
385	    njs_value_t *dst)
386	{
387	    njs_int_t  ret;
388	
389	    if (njs_is_function(value)) {
390	        *dst = *value;
391	        return NJS_OK;
392	    }
393	
394	    ret = njs_value_property(vm, value, NJS_ATOM_STRING_constructor, dst);
395	    if (njs_slow_path(ret == NJS_ERROR)) {
396	        return ret;
397	    }
398	
399	    if (!njs_is_function(dst)) {
400	        njs_type_error(vm, "the object does not contain a constructor");
401	        return NJS_ERROR;
402	    }
403	
404	    return NJS_OK;
405	}
406	
407	
408	static njs_int_t
409	njs_promise_capability_executor(njs_vm_t *vm, njs_value_t *args,
410	    njs_uint_t nargs, njs_index_t unused, njs_value_t *retval)
411	{
412	    njs_promise_context_t     *context;
413	    njs_promise_capability_t  *capability;
414	
415	    context = vm->top_frame->function->context;
416	    capability = context->capability;
417	
418	    if (njs_slow_path(capability == NULL)) {
419	        njs_type_error(vm, "failed to get function capability");
420	        return NJS_ERROR;
421	    }
422	
423	    if (!njs_is_undefined(&capability->resolve)) {
424	        njs_type_error(vm, "capability resolve slot is not undefined");
425	        return NJS_ERROR;
426	    }
427	
428	    if (!njs_is_undefined(&capability->reject)) {
429	        njs_type_error(vm, "capability reject slot is not undefined");
430	        return NJS_ERROR;
431	    }
432	
433	    capability->resolve = *njs_arg(args, nargs, 1);
434	    capability->reject = *njs_arg(args, nargs, 2);
435	
436	    njs_value_assign(retval, &njs_value_undefined);
437	
438	    return NJS_OK;
439	}
440	
441	
442	njs_inline njs_value_t *
443	njs_promise_trigger_reactions(njs_vm_t *vm, njs_value_t *value,
444	    njs_queue_t *queue)
445	{
446	    njs_int_t               ret;
447	    njs_value_t             arguments[2];
448	    njs_function_t          *function;
449	    njs_queue_link_t        *link;
450	    njs_promise_reaction_t  *reaction;
451	
452	    for (link = njs_queue_first(queue);
453	         link != njs_queue_tail(queue);
454	         link = njs_queue_next(link))
455	    {
456	        reaction = njs_queue_link_data(link, njs_promise_reaction_t, link);
457	
458	        function = njs_promise_create_function(vm,
459	                                               sizeof(njs_promise_context_t));
460	        if (njs_slow_path(function == NULL)) {
461	            return njs_value_arg(&njs_value_null);
462	        }
463	
464	        function->u.native = njs_promise_reaction_job;
465	
466	        njs_set_data(&arguments[0], reaction, 0);
467	        arguments[1] = *value;
468	
469	        ret = njs_vm_enqueue_job(vm, function, arguments, 2);
470	        if (njs_slow_path(ret != NJS_OK)) {
471	            return njs_value_arg(&njs_value_null);
472	        }
473	    }
474	
475	    return njs_value_arg(&njs_value_undefined);
476	}
477	
478	
479	njs_inline njs_value_t *
480	njs_promise_fulfill(njs_vm_t *vm, njs_promise_t *promise, njs_value_t *value)
481	{
482	    njs_queue_t         queue;
483	    njs_promise_data_t  *data;
484	
485	    data = njs_data(&promise->value);
486	
487	    data->result = *value;
488	    data->state = NJS_PROMISE_FULFILL;
489	
490	    if (njs_queue_is_empty(&data->fulfill_queue)) {
491	        return njs_value_arg(&njs_value_undefined);
492	
493	    } else {
494	        queue = data->fulfill_queue;
495	
496	        queue.head.prev->next = &queue.head;
497	        queue.head.next->prev = &queue.head;
498	    }
499	
500	    njs_queue_init(&data->fulfill_queue);
501	    njs_queue_init(&data->reject_queue);
502	
503	    return njs_promise_trigger_reactions(vm, value, &queue);
504	}
