507	njs_inline njs_value_t *
508	njs_promise_reject(njs_vm_t *vm, njs_promise_t *promise, njs_value_t *reason)
509	{
510	    njs_queue_t         queue;
511	    njs_value_t         promise_value;
512	    njs_promise_data_t  *data;
513	
514	    data = njs_data(&promise->value);
515	
516	    data->result = *reason;
517	    data->state = NJS_PROMISE_REJECTED;
518	
519	    if (!data->is_handled) {
520	        if (vm->rejection_tracker != NULL) {
521	            njs_set_promise(&promise_value, promise);
522	            vm->rejection_tracker(vm, vm->rejection_tracker_opaque, 0,
523	                                  &promise_value, reason);
524	        }
525	    }
526	
527	    if (njs_queue_is_empty(&data->reject_queue)) {
528	        return njs_value_arg(&njs_value_undefined);
529	
530	    } else {
531	        queue = data->reject_queue;
532	
533	        queue.head.prev->next = &queue.head;
534	        queue.head.next->prev = &queue.head;
535	    }
536	
537	    njs_queue_init(&data->fulfill_queue);
538	    njs_queue_init(&data->reject_queue);
539	
540	    return njs_promise_trigger_reactions(vm, reason, &queue);
