550	
551	    ret = njs_value_property(vm, promise, NJS_ATOM_STRING_then, &function);
552	    if (njs_slow_path(ret != NJS_OK)) {
553	        if (ret == NJS_DECLINED) {
554	            goto failed;
555	        }
556	
557	        return NJS_ERROR;
558	    }
559	
560	    if (njs_fast_path(njs_is_function(&function))) {
561	        return njs_function_call(vm, njs_function(&function), promise, args,
562	                                 nargs, retval);
