573	static njs_int_t
574	njs_promise_resolve_function(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
575	    njs_index_t unused, njs_value_t *retval)
576	{
577	    njs_int_t              ret;
578	    njs_value_t            *resolution, error, then, arguments[3];
579	    njs_promise_t          *promise;
580	    njs_function_t         *function;
581	    njs_native_frame_t     *active_frame;
582	    njs_promise_context_t  *context;
583	
584	    active_frame = vm->top_frame;
585	    context = active_frame->function->context;
586	    promise = njs_promise(&context->promise);
587	
588	    if (*context->resolved_ref) {
589	        njs_value_assign(retval, &njs_value_undefined);
590	        return NJS_OK;
591	    }
592	
593	    *context->resolved_ref = 1;
594	
595	    resolution = njs_arg(args, nargs, 1);
596	
597	    if (njs_values_same(vm, resolution, &context->promise)) {
598	        njs_error_fmt_new(vm, &error, NJS_OBJ_TYPE_TYPE_ERROR,
599	                          "promise self resolution");
600	        if (njs_slow_path(!njs_is_error(&error))) {
601	            return NJS_ERROR;
602	        }
603	
604	        njs_value_assign(retval, njs_promise_reject(vm, promise, &error));
605	
606	        return NJS_OK;
607	    }
608	
609	    if (!njs_is_object(resolution)) {
610	        goto fulfill;
611	    }
612	
613	    ret = njs_value_property(vm, resolution, NJS_ATOM_STRING_then, &then);
614	    if (njs_slow_path(ret == NJS_ERROR)) {
615	        if (njs_slow_path(njs_is_memory_error(vm, &vm->exception))) {
616	            return NJS_ERROR;
617	        }
618	
619	        error = njs_vm_exception(vm);
620	        njs_value_assign(retval, njs_promise_reject(vm, promise, &error));
621	
622	        if (njs_slow_path(njs_is_null(retval))) {
623	            return NJS_ERROR;
624	        }
625	
626	        return NJS_OK;
627	    }
628	
629	    if (!njs_is_function(&then)) {
630	        goto fulfill;
631	    }
632	
633	    arguments[0] = context->promise;
634	    arguments[1] = *resolution;
635	    arguments[2] = then;
636	
637	    function = njs_promise_create_function(vm, sizeof(njs_promise_context_t));
638	    if (njs_slow_path(function == NULL)) {
639	        return NJS_ERROR;
640	    }
641	
642	    function->u.native = njs_promise_resolve_thenable_job;
643	
644	    ret = njs_vm_enqueue_job(vm, function, arguments, 3);
645	    if (njs_slow_path(ret != NJS_OK)) {
646	        return ret;
647	    }
648	
649	    njs_value_assign(retval, &njs_value_undefined);
650	
651	    return NJS_OK;
652	
653	fulfill:
654	
655	    njs_value_assign(retval, njs_promise_fulfill(vm, promise, resolution));
656	    if (njs_slow_path(njs_is_null(retval))) {
657	        return NJS_ERROR;
658	    }
659	
660	    return NJS_OK;
661	}
