825	njs_int_t
826	njs_promise_perform_then(njs_vm_t *vm, njs_value_t *value,
827	    njs_value_t *fulfilled, njs_value_t *rejected,
828	    njs_promise_capability_t *capability, njs_value_t *retval)
829	{
830	    njs_int_t               ret;
831	    njs_value_t             arguments[2], promise_value;
832	    njs_promise_t           *promise;
833	    njs_function_t          *function;
834	    njs_promise_data_t      *data;
835	    njs_promise_reaction_t  *fulfilled_reaction, *rejected_reaction;
836	
837	    njs_assert(njs_is_promise(value));
838	
839	    if (!njs_is_function(fulfilled)) {
840	        fulfilled = njs_value_arg(&njs_value_undefined);
841	    }
842	
843	    if (!njs_is_function(rejected)) {
844	        rejected = njs_value_arg(&njs_value_undefined);
845	    }
846	
847	    promise = njs_promise(value);
848	    data = njs_data(&promise->value);
849	
850	    fulfilled_reaction = njs_mp_alloc(vm->mem_pool,
851	                                      sizeof(njs_promise_reaction_t));
852	    if (njs_slow_path(fulfilled_reaction == NULL)) {
853	        njs_memory_error(vm);
854	        return NJS_ERROR;
855	    }
856	
857	    fulfilled_reaction->capability = capability;
858	    fulfilled_reaction->handler = *fulfilled;
859	    fulfilled_reaction->type = NJS_PROMISE_FULFILL;
860	
861	    rejected_reaction = njs_mp_alloc(vm->mem_pool,
862	                                     sizeof(njs_promise_reaction_t));
863	    if (njs_slow_path(rejected_reaction == NULL)) {
864	        njs_memory_error(vm);
865	        return NJS_ERROR;
866	    }
867	
868	    rejected_reaction->capability = capability;
869	    rejected_reaction->handler = *rejected;
870	    rejected_reaction->type = NJS_PROMISE_REJECTED;
871	
872	    if (data->state == NJS_PROMISE_PENDING) {
873	        njs_queue_insert_tail(&data->fulfill_queue, &fulfilled_reaction->link);
874	        njs_queue_insert_tail(&data->reject_queue, &rejected_reaction->link);
875	
876	    } else {
877	        function = njs_promise_create_function(vm,
878	                                               sizeof(njs_promise_context_t));
879	        if (njs_slow_path(function == NULL)) {
880	            return NJS_ERROR;
881	        }
882	
883	        function->u.native = njs_promise_reaction_job;
884	
885	        if (data->state == NJS_PROMISE_REJECTED) {
886	            njs_set_data(&arguments[0], rejected_reaction, 0);
887	
888	            if (vm->rejection_tracker != NULL) {
889	                njs_set_promise(&promise_value, promise);
890	                vm->rejection_tracker(vm, vm->rejection_tracker_opaque, 1,
891	                                      &promise_value, &data->result);
892	            }
893	
894	        } else {
895	            njs_set_data(&arguments[0], fulfilled_reaction, 0);
896	        }
897	
898	        arguments[1] = data->result;
899	
900	        ret = njs_vm_enqueue_job(vm, function, arguments, 2);
901	        if (njs_slow_path(ret != NJS_OK)) {
902	            return ret;
903	        }
904	    }
905	
906	    data->is_handled = 1;
907	
908	    if (capability == NULL) {
909	        njs_set_undefined(retval);
910	
911	    } else {
912	        njs_value_assign(retval, &capability->promise);
913	    }
914	
915	    return NJS_OK;
916	}
