1087	static njs_int_t
1088	njs_promise_reaction_job(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1089	    njs_index_t unused, njs_value_t *retval)
1090	{
1091	    njs_int_t                 ret;
1092	    njs_bool_t                is_error;
1093	    njs_value_t               value, *argument;
1094	    njs_promise_reaction_t    *reaction;
1095	    njs_promise_capability_t  *capability;
1096	
1097	    reaction = njs_data(njs_arg(args, nargs, 1));
1098	    argument = njs_arg(args, nargs, 2);
1099	    capability = reaction->capability;
1100	
1101	    is_error = 0;
1102	
